  "inlineSchema": "// This is your Prisma schema file\n// Learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n\n// User model for authentication\nmodel User {\n  id            String        @id @default(uuid())\n  email         String        @unique\n  passwordHash  String\n  fullName      String\n  rollNo        String?       @unique\n  createdAt     DateTime      @default(now())\n  updatedAt     DateTime      @updatedAt\n  \n  // Relations\n  roles         UserRole[]\n  hallTickets   HallTicket[]\n  studentCourses StudentCourse[]\n  mindMaps      MindMap[]\n  createdEvents  Event[]       @relation(\"EventCreator\")\n  managedClubs  Club[]         @relation(\"ClubCoordinator\")\n  seatingAllocations SeatingAllocation[]\n}\n\n// Role model for role-based access control\nmodel Role {\n  id        Int       @id @default(autoincrement())\n  name      String    @unique // STUDENT, ADMIN, SEATING_MANAGER, CLUB_COORDINATOR\n  users     UserRole[]\n  createdAt DateTime  @default(now())\n}\n\n// Join table for User and Role many-to-many relationship\nmodel UserRole {\n  userId    String   @map(\"user_id\")\n  roleId    Int      @map(\"role_id\")\n  assignedAt DateTime @default(now())\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  role      Role     @relation(fields: [roleId], references: [id], onDelete: Cascade)\n\n  @@id([userId, roleId])\n}\n\n// Course model for academic courses\nmodel Course {\n  id          String         @id @default(uuid())\n  code        String         @unique\n  name        String\n  semester    Int\n  department  String\n  createdAt   DateTime       @default(now())\n  updatedAt   DateTime       @updatedAt\n  \n  // Relations\n  syllabus    Syllabus[]\n  exams       Exam[]\n  studentCourses StudentCourse[]\n}\n\n// Syllabus model for course content\nmodel Syllabus {\n  id          String    @id @default(uuid())\n  courseId    String    @map(\"course_id\")\n  content     String    // Could be JSON string or markdown\n  sourcePdfUrl String?  @map(\"source_pdf_url\")\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  \n  // Relations\n  course      Course    @relation(fields: [courseId], references: [id])\n  mindMaps    MindMap[]\n}\n\n// Student enrollment in courses\nmodel StudentCourse {\n  id         String   @id @default(uuid())\n  studentId  String   @map(\"student_id\")\n  courseId   String   @map(\"course_id\")\n  enrolledAt DateTime @default(now())\n  \n  // Relations\n  student    User     @relation(fields: [studentId], references: [id])\n  course     Course   @relation(fields: [courseId], references: [id])\n  \n  @@unique([studentId, courseId])\n}\n\n// Exam model for tests and assessments\nmodel Exam {\n  id          String    @id @default(uuid())\n  courseId    String    @map(\"course_id\")\n  examType    String    // MID1, MID2, END, etc.\n  examDate    DateTime\n  startTime   DateTime\n  endTime     DateTime\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  \n  // Relations\n  course      Course    @relation(fields: [courseId], references: [id])\n  hallTickets HallTicket[]\n  seatingAllocations SeatingAllocation[]\n}\n\n// Hall tickets for exams\nmodel HallTicket {\n  id        String    @id @default(uuid())\n  studentId String    @map(\"student_id\")\n  examId    String    @map(\"exam_id\")\n  issueDate DateTime  @default(now())\n  qrCode    String    @map(\"qr_code\")\n  \n  // Relations\n  student   User      @relation(fields: [studentId], references: [id])\n  exam      Exam      @relation(fields: [examId], references: [id])\n  \n  @@unique([studentId, examId])\n}\n\n// Room for exam seating\nmodel Room {\n  id       String   @id @default(uuid())\n  name     String   @unique // e.g., A-101\n  capacity Int\n  rows     Int\n  cols     Int\n  \n  // Relations\n  seats    Seat[]\n}\n\n// Seats within rooms\nmodel Seat {\n  id         String   @id @default(uuid())\n  roomId     String   @map(\"room_id\")\n  rowNumber  Int      @map(\"row_number\")\n  colNumber  Int      @map(\"col_number\")\n  \n  // Relations\n  room       Room     @relation(fields: [roomId], references: [id])\n  allocations SeatingAllocation[]\n  \n  @@unique([roomId, rowNumber, colNumber])\n}\n\n// Seating allocation for exams\nmodel SeatingAllocation {\n  id        String    @id @default(uuid())\n  examId    String    @map(\"exam_id\")\n  studentId String    @map(\"student_id\")\n  seatId    String    @map(\"seat_id\")\n  allocatedAt DateTime @default(now())\n  \n  // Relations\n  exam      Exam      @relation(fields: [examId], references: [id])\n  student   User      @relation(fields: [studentId], references: [id])\n  seat      Seat      @relation(fields: [seatId], references: [id])\n  \n  @@unique([examId, studentId])\n  @@unique([examId, seatId])\n}\n\n// Mind map model for study support\nmodel MindMap {\n  id         String       @id @default(uuid())\n  studentId  String       @map(\"student_id\")\n  syllabusId String       @map(\"syllabus_id\")\n  title      String\n  createdAt  DateTime     @default(now())\n  updatedAt  DateTime     @updatedAt\n  \n  student    User         @relation(fields: [studentId], references: [id])\n  syllabus   Syllabus     @relation(fields: [syllabusId], references: [id])\n  nodes      MindMapNode[] @relation(\"MindMapNodes\")\n}\n\nmodel MindMapNode {\n  id         String       @id @default(uuid())\n  mindmapId  String       @map(\"mindmap_id\")\n  parentId   String?      @map(\"parent_id\")\n  label      String\n  notes      String?\n  orderIndex Int          @default(0)\n  \n  mindmap    MindMap      @relation(\"MindMapNodes\", fields: [mindmapId], references: [id])\n  parent     MindMapNode? @relation(\"ChildNodes\", fields: [parentId], references: [id])\n  children   MindMapNode[] @relation(\"ChildNodes\")\n  resources  StudyResource[]\n}\n\n// Study resources linked to mind map nodes\nmodel StudyResource {\n  id           String      @id @default(uuid())\n  mindmapNodeId String     @map(\"mindmap_node_id\")\n  type         String      // VIDEO, PDF, LINK, etc.\n  url          String\n  title        String\n  \n  // Relations\n  mindmapNode  MindMapNode @relation(fields: [mindmapNodeId], references: [id])\n}\n\n// Club model for student organizations\nmodel Club {\n  id            String    @id @default(uuid())\n  name          String    @unique\n  description   String?\n  coordinatorId String    @map(\"coordinator_id\")\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n  \n  // Relations\n  coordinator  User      @relation(\"ClubCoordinator\", fields: [coordinatorId], references: [id])\n  events       Event[]\n}\n\n// Event model for club activities\nmodel Event {\n  id            String    @id @default(uuid())\n  clubId        String    @map(\"club_id\")\n  title         String\n  description   String?\n  startDateTime DateTime  @map(\"start_date_time\")\n  endDateTime   DateTime  @map(\"end_date_time\")\n  location      String?\n  status        String    @default(\"PENDING\") // PENDING, APPROVED, REJECTED\n  createdById   String    @map(\"created_by_id\")\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n  \n  // Relations\n  club         Club      @relation(fields: [clubId], references: [id])\n  createdBy    User      @relation(\"EventCreator\", fields: [createdById], references: [id])\n  documents    EventDocument[]\n}\n\n// Documents associated with events\nmodel EventDocument {\n  id        String    @id @default(uuid())\n  eventId   String    @map(\"event_id\")\n  fileUrl   String    @map(\"file_url\")\n  fileType  String    @map(\"file_type\") // PDF, DOC, etc.\n  uploadedAt DateTime  @default(now())\n  \n  // Relations\n  event      Event     @relation(fields: [eventId], references: [id])\n}\n",
